form:Form.form:Scripts:
		function EnableControl()
{ 
	var estado;                     

	if (Ctrl('LIST'))
	{                     
		estado = Ctrl("LIST").GetSelectAttrValue("c_estado");
	} else
	{
		estado = Ctrl('c_estado').GetXValue();
	}                                    

	switch(estado)
	{            
		case "A":
			CtrlEnabled("f_desde"     , true );
			CtrlEnabled("f_hasta"     , true );
			CtrlEnabled("oi_escala"   , true );
			CtrlEnabled("MAIN_GRID"   , true );

			CtrlEnabled("ADMINISTRAR" , true );
			CtrlEnabled("deshabilitar", false);
			CtrlEnabled("habilitar"   , false);
			CtrlEnabled("cerrar"      , false);

			CtrlEnabled("EDIT"        , true );
			CtrlEnabled("DELETE"      , true );
		break;

		case "I":
			CtrlEnabled("f_desde"     , true );
			CtrlEnabled("f_hasta"     , true );
			CtrlEnabled("oi_escala"   , true );
			CtrlEnabled("MAIN_GRID"   , true );

			CtrlEnabled("ADMINISTRAR" , true ); 
			CtrlEnabled("deshabilitar", false);
			CtrlEnabled("habilitar"   , true );
			CtrlEnabled("cerrar"      , false);

			CtrlEnabled("EDIT"        , true );
			CtrlEnabled("DELETE"      , false);
		break;

		case "H":
			CtrlEnabled("f_desde"     , false);
			CtrlEnabled("f_hasta"     , false);
			CtrlEnabled("oi_escala"   , false);
			CtrlEnabled("MAIN_GRID"   , false);

			CtrlEnabled("ADMINISTRAR" , true );
			CtrlEnabled("deshabilitar", true );
			CtrlEnabled("habilitar"   , false);
			CtrlEnabled("cerrar"      , true );

			CtrlEnabled("EDIT"        , true);
			CtrlEnabled("DELETE"      , false);
		break;

		case "C":
			CtrlEnabled("f_desde"     , false);
			CtrlEnabled("f_hasta"     , false);
			CtrlEnabled("oi_escala"   , false);
			CtrlEnabled("MAIN_GRID"   , false);

			CtrlEnabled("ADMINISTRAR" , false); 
			CtrlEnabled("deshabilitar", false);
			CtrlEnabled("habilitar"   , false);
			CtrlEnabled("cerrar"      , false);

			CtrlEnabled("EDIT"        , false);
			CtrlEnabled("DELETE"      , false);
		break; 

		default:
			CtrlEnabled("f_desde"     , false);
			CtrlEnabled("f_hasta"     , false);
			CtrlEnabled("oi_escala"   , false);
			CtrlEnabled("MAIN_GRID"   , false);

			CtrlEnabled("ADMINISTRAR" , false);
			CtrlEnabled("deshabilitar", false);
			CtrlEnabled("habilitar"   , false);
			CtrlEnabled("cerrar"      , true );

			CtrlEnabled("EDIT"        , false);
			CtrlEnabled("DELETE"      , false);
		break;

	}
}


function OnLoad()
{	                      
	EnableControl();
}
